#include <bits/stdc++.h>using namespace std;typedef long long ll;int main(){    ll t;    cin>>t;    while(t--){      ll n,k,p,m;      cin>>n>>k>>p>>m;      vector<ll> a(n,0);      for(int i=0;i<n;i++){        cin>>a[i];      }      ll ans=0;      if(p<=k){        if(m-a[p-1]>=0){          m-=a[p-1];          ans++;        }      }      else{        priority_queue<ll> q;        ll sz=p-k;        for(int i=0;i<p-1;i++){          if(i!=(p-1)){            q.push(a[i]);          }          if(q.size()>sz){            q.pop();          }        }        ll s=0;        while(!q.empty()){          s+=q.top();          q.pop();        }        if(m-s-a[p-1]>=0){          m-=s+a[p-1];          ans++;        }      }      priority_queue<ll> pq;      ll sz=n-k;      for(int i=0;i<n;i++){        if(i!=(p-1)){          pq.push(a[i]);        }        if(pq.size()>sz){          pq.pop();        }      }      ll sum=0;      while(!pq.empty()){        sum+=pq.top();        pq.pop();      }      sum+=a[p-1];      while(m-sum>=0){        ans++;        m-=sum;      }      cout<<ans<<endl;    }}